import chalk from "chalk";
import { config, ensureRuntimeDirectories } from "./config.js";
import { logger } from "./logger.js";
import { createTools } from "./tools/index.js";
import { GradeService } from "./services/grade-service.js";
import { GradeAgent } from "./agent/grade-agent.js";
import { WhatsAppHandler } from "./whatsapp/handler.js";

async function bootstrap() {
  ensureRuntimeDirectories();
  logger.info(
    `${config.app.name} starting. Data directory: ${config.paths.data} | Model: ${config.ollama.model}`,
  );
  logger.info(
    `Single-number mode=${config.app.singleNumberMode} | loopGuard ttl=${config.loopGuard.processedMessageTtlMs}ms idTtl=${config.loopGuard.botMessageIdTtlMs}ms textTtl=${config.loopGuard.botMessageTextTtlMs}ms`,
  );
  logger.info(
    `Reply routing strategy=${config.replyRouting.strategy} fallback=${config.replyRouting.enableFallback} verifyTimeout=${config.replyRouting.verifyTimeoutMs}ms`,
  );
  process.stdout.write(
    chalk.green(
      `${config.app.name} is booting. Scan QR code in terminal once WhatsApp starts.\n`,
    ),
  );

  const tools = createTools({ config, logger });
  const gradeService = new GradeService({
    config,
    logger,
    excelTool: tools.excel,
    pythonBridge: tools.pythonBridge,
  });
  const agent = new GradeAgent({ config, logger, tools, gradeService });
  const whatsapp = new WhatsAppHandler({ config, logger, agent });

  await whatsapp.start();

  process.on("SIGINT", () => {
    logger.info("Shutting down on SIGINT.");
    process.exit(0);
  });
  process.on("SIGTERM", () => {
    logger.info("Shutting down on SIGTERM.");
    process.exit(0);
  });
}

bootstrap().catch((error) => {
  logger.error(`Fatal startup error: ${error.stack || error.message}`);
  process.exit(1);
});

