  1→import pRetry from "p-retry";
  2→import { parseStudentScorePairs, parseYesNo } from "../tools/common.js";
  3→import { postOllamaChat } from "../tools/ollama-http.js";
  4→
  5→const SYSTEM_PROMPT =
  6→  "You are GradeBot, a reliable and accurate assistant for teachers. Your job is to eliminate all manual grade encoding and calculations so teachers have more time for actual teaching. Always reply in clear English. Never guess numbers. Always create a timestamped backup before any change. Always ask for explicit yes/no confirmation before writing or overwriting any file. Use the Python tools for all calculations, statistics, and reports. Be concise, professional, and proactive. You are powered by Qwen3-VL which excels at reading score sheets from photos.";
  7→
  8→function extractClassFileHint(text) {
  9→  if (!text) return null;
 10→  const match = text.match(/(?:for|to|in|as)\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i);
 11→  return match ? match[1] : null;
 12→}
 13→
 14→function parseRuleBasedIntent(text) {
 15→  if (!text) return { intent: "unknown" };
 16→  const normalized = text.trim();
 17→
 18→  const summarizeMatch = normalized.match(
 19→    /(?:summarize|summary|analy[sz]e|overview|insights?|stats?).*(?:for|of|on|my)?\s*([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
 20→  );
 21→  if (summarizeMatch) {
 22→    return { intent: "calculate_stats", classFile: summarizeMatch[1] };
 23→  }
 24→
 25→  const addMatch = normalized.match(/^add to\s+([^\s:]+)\s*:\s*(.+)$/i);
 26→  if (addMatch) {
 27→    return {
 28→      intent: "add_scores",
 29→      classFile: addMatch[1],
 30→      studentScores: parseStudentScorePairs(addMatch[2]),
 31→    };
 32→  }
 33→
 34→  const statsMatch = normalized.match(
 35→    /(?:calculate|compute).*(?:full\s+)?(?:stats|statistics|rankings).*(?:for|on)\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
 36→  );
 37→  if (statsMatch) {
 38→    return { intent: "calculate_stats", classFile: statsMatch[1] };
 39→  }
 40→
 41→  const reportMatch = normalized.match(
 42→    /generate.*(?:parent\s+)?(?:pdf\s+)?report.*for\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
 43→  );
 44→  if (reportMatch) {
 45→    return { intent: "generate_report", classFile: reportMatch[1] };
 46→  }
 47→
 48→  const curveMatch = normalized.match(
 49→    /apply\s+(gentle|bell|custom)?\s*curve\s+(?:to|for)\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
 50→  );
 51→  if (curveMatch) {
 52→    const modeHint = (curveMatch[1] || "gentle").toLowerCase();
 53→    const mode =
 54→      modeHint === "custom"
 55→        ? "custom_linear"
 56→        : modeHint === "bell"
 57→          ? "bell"
 58→          : "gentle_bell";
 59→    return { intent: "apply_curve", classFile: curveMatch[2], mode };
 60→  }
 61→
 62→  if (/backup all/i.test(normalized)) {
 63→    return { intent: "backup_all" };
 64→  }
 65→
 66→  const importMatch = normalized.match(
 67→    /(?:import|use)\s+(?:as\s+)?([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
 68→  );
 69→  if (importMatch) {
 70→    return { intent: "import_document", classFile: importMatch[1] };
 71→  }
 72→
 73→  if (/^(help|menu|what can you do)\b/i.test(normalized)) {
 74→    return { intent: "help" };
 75→  }
 76→
 77→  return { intent: "unknown" };
 78→}
 79→
 80→function parseJsonLoose(rawText) {
 81→  const text = String(rawText || "").trim();
 82→  if (!text) return null;
 83→  try {
 84→    return JSON.parse(text);
 85→  } catch {
 86→    const firstBrace = text.indexOf("{");
 87→    const lastBrace = text.lastIndexOf("}");
 88→    if (firstBrace >= 0 && lastBrace > firstBrace) {
 89→      try {
 90→        return JSON.parse(text.slice(firstBrace, lastBrace + 1));
 91→      } catch {
 92→        return null;
 93→      }
 94→    }
 95→    return null;
 96→  }
 97→}
 98→
 99→function helpMessage() {
100→  return [
101→    "I can help with grade encoding, calculations, and reporting.",
102→    "Examples:",
103→    "- Add to math.xlsx: Alice 94, Bob 87, Charlie 91",
104→    "- Calculate full stats and rankings for science.xlsx",
105→    "- Generate parent PDF report for english.xlsx",
106→    "- Apply gentle curve to class1.xlsx",
107→    "- Backup all my files",
108→    "You can also send an Excel/CSV file or a photo of a paper score sheet.",
109→  ].join("\n");
110→}
111→
112→export class GradeAgent {
113→  constructor({ config, logger, tools, gradeService }) {
114→    this.config = config;
115→    this.logger = logger;
116→    this.tools = tools;
117→    this.gradeService = gradeService;
118→    this.actions = tools.createActionTools(gradeService);
119→  }
120→
121→  async inferIntentWithOllama(userId, text) {
122→    const memory = await this.gradeService.readUserMemory(userId);
123→    const historySnippet = (memory.history || [])
124→      .slice(-6)
125→      .map((item) => `${item.role}: ${item.text}`)
126→      .join("\n");
127→
128→    const extractionPrompt = [
129→      "Extract teacher intent from the message.",
130→      "Return strict JSON with fields:",
131→      '{ "intent": "add_scores|calculate_stats|generate_report|apply_curve|backup_all|import_document|help|unknown", "classFile": "optional", "studentScores":[{"student":"Name","score":90}], "mode":"optional" }',
132→      "Rules:",
133→      "- Do not invent student scores.",
134→      "- Keep classFile null if not provided.",
135→      "- studentScores must be empty unless clearly provided.",
136→      "",
137→      "Recent conversation:",
138→      historySnippet || "(none)",
139→      "",
140→      `Current message: ${text}`,
141→    ].join("\n");
142→
143→    const doRequest = async () => {
144→      const response = await postOllamaChat({
145→        baseUrl: this.config.ollama.baseUrl,
146→        model: this.config.ollama.model,
147→        messages: [
148→          { role: "system", content: SYSTEM_PROMPT },
149→          { role: "user", content: extractionPrompt },
150→        ],
151→        timeoutMs: this.config.ollama.requestTimeoutMs,
152→        logger: this.logger,
153→        stream: false,
154→      });
155→      return response?.data?.message?.content;
156→    };
157→
158→    const content = await pRetry(doRequest, {
159→      retries: Math.max(0, (this.config.ollama.retries || 1) - 1),
160→      factor: 2,
161→      minTimeout: 600,
162→      maxTimeout: 5000,
163→      onFailedAttempt: (error) => {
164→        this.logger.warn(`Intent extraction retry ${error.attemptNumber}: ${error.message}`);
165→      },
166→    });
167→
168→    return parseJsonLoose(content) || { intent: "unknown" };
169→  }
170→
171→  async inferIntent(userId, text) {
172→    const ruleBased = parseRuleBasedIntent(text);
173→    if (ruleBased.intent !== "unknown") {
174→      return ruleBased;
175→    }
176→    if (!text || text.trim().length < 2) {
177→      return { intent: "unknown" };
178→    }
179→    try {
180→      const ollamaIntent = await this.inferIntentWithOllama(userId, text);
181→      return {
182→        intent: ollamaIntent.intent || "unknown",
183→        classFile: ollamaIntent.classFile || null,
184→        studentScores: Array.isArray(ollamaIntent.studentScores)
185→          ? ollamaIntent.studentScores
186→          : [],
187→        mode: ollamaIntent.mode || null,
188→      };
189→    } catch (error) {
190→      this.logger.error(`Intent inference failed: ${error.message}`);
191→      return { intent: "unknown" };
192→    }
193→  }
194→
195→  async handleImageAttachment(input, imageAttachment) {
196→    const classFileHint = extractClassFileHint(input.text || "");
197→    const visionResult = await this.tools.vision.extractScoresFromImage({
198→      imagePath: imageAttachment.path,
199→      suggestedClassFile: classFileHint || "class1.xlsx",
200→    });
201→
202→    if (!visionResult.rows.length) {
203→      const warningText = visionResult.warnings.length
204→        ? `\nWarnings:\n- ${visionResult.warnings.join("\n- ")}`
205→        : "";
206→      return {
207→        replyText: `I could not extract usable scores from that image.${warningText}`,
208→      };
209→    }
210→
211→    const prepared = await this.actions.processPhoto.execute(
212→      { userId: input.userId },
213→      {
214→        classFile: visionResult.classFile,
215→        rows: visionResult.rows,
216→      },
217→    );
218→
219→    const extractedPreview = visionResult.rows
220→      .slice(0, 8)
221→      .map((row) => `- ${row.student}: ${row.score}`)
222→      .join("\n");
223→    const warnings = visionResult.warnings.length
224→      ? `\nOCR notes:\n- ${visionResult.warnings.join("\n- ")}`
225→      : "";
226→
227→    return {
228→      replyText: [
229→        "I extracted the following scores from your photo:",
230→        extractedPreview,
231→        warnings,
232→        "",
233→        prepared.replyText,
234→      ]
235→        .filter(Boolean)
236→        .join("\n"),
237→    };
238→  }
239→
240→  async handleDocumentAttachment(input, docAttachment) {
241→    await this.gradeService.setLastUploadedDocument(input.userId, {
242→      path: docAttachment.path,
243→      originalName: docAttachment.originalName || "uploaded.xlsx",
244→      mime: docAttachment.mime,
245→      receivedAt: new Date().toISOString(),
246→    });
247→
248→    const text = input.text || "";
249→    if (/import|use as/i.test(text)) {
250→      const classFileHint = extractClassFileHint(text) || docAttachment.originalName;
251→      return this.actions.importDocument.execute(
252→        { userId: input.userId },
253→        {
254→          documentPath: docAttachment.path,
255→          originalName: docAttachment.originalName,
256→          classFile: classFileHint,
257→        },
258→      );
259→    }
260→
261→    return {
262→      replyText: [
263→        `I received your file: ${docAttachment.originalName || "uploaded file"}.`,
264→        "What would you like me to do next?",
265→        "- Import it to managed grades storage",
266→        "- Calculate full stats and rankings",
267→        "- Generate a parent PDF report",
268→        "- Apply a gentle curve",
269→        "You can reply with: Import as class1.xlsx",
270→      ].join("\n"),
271→    };
272→  }
273→
274→  async handleTextIntent(input, intent) {
275→    const context = { userId: input.userId };
276→    switch (intent.intent) {
277→      case "add_scores":
278→        return this.actions.addScores.execute(context, {
279→          classFile: intent.classFile,
280→          studentScores: intent.studentScores || [],
281→        });
282→      case "calculate_stats":
283→        return this.actions.calculateStats.execute(context, {
284→          classFile: intent.classFile,
285→        });
286→      case "generate_report":
287→        return this.actions.generateReport.execute(context, {
288→          classFile: intent.classFile,
289→        });
290→      case "apply_curve":
291→        return this.actions.applyCurve.execute(context, {
292→          classFile: intent.classFile,
293→          mode: intent.mode || "gentle_bell",
294→        });
295→      case "backup_all":
296→        return this.actions.backupAll.execute(context, {});
297→      case "import_document": {
298→        const uploaded = await this.gradeService.getLastUploadedDocument(input.userId);
299→        if (!uploaded) {
300→          return {
301→            replyText:
302→              "Please send an Excel or CSV file first, then I can import it for you.",
303→          };
304→        }
305→        return this.actions.importDocument.execute(context, {
306→          documentPath: uploaded.path,
307→          originalName: uploaded.originalName,
308→          classFile: intent.classFile || uploaded.originalName,
309→        });
310→      }
311→      case "help":
312→        return { replyText: helpMessage() };
