import { createExcelTool } from "./excel.js";
import { createVisionTool } from "./vision.js";
import { createPythonBridge } from "./python-bridge.js";

export function createTools({ config, logger }) {
  const excel = createExcelTool({ config, logger });
  const vision = createVisionTool({ config, logger });
  const pythonBridge = createPythonBridge({ config, logger });

  function createActionTools(gradeService) {
    return {
      addScores: {
        name: "add_scores",
        description: "Add or update scores in a class file.",
        requiresConfirmation: true,
        execute: (context, args) => gradeService.prepareAddScores(context, args),
      },
      calculateStats: {
        name: "calculate_stats",
        description: "Compute full statistics and rankings.",
        requiresConfirmation: false,
        execute: (context, args) => gradeService.calculateStats(context, args),
      },
      generateReport: {
        name: "generate_report",
        description: "Generate a parent-friendly PDF report.",
        requiresConfirmation: true,
        execute: (context, args) => gradeService.prepareGenerateReport(context, args),
      },
      applyCurve: {
        name: "apply_curve",
        description: "Apply grade curve with safe validation.",
        requiresConfirmation: true,
        execute: (context, args) => gradeService.prepareApplyCurve(context, args),
      },
      backupAll: {
        name: "backup_all",
        description: "Create backups for all managed grade files.",
        requiresConfirmation: true,
        execute: (context, args) => gradeService.prepareBackupAll(context, args),
      },
      processPhoto: {
        name: "process_photo",
        description: "Extract scores from an uploaded photo.",
        requiresConfirmation: true,
        execute: (context, args) => gradeService.preparePhotoSave(context, args),
      },
      importDocument: {
        name: "import_document",
        description: "Import uploaded grade file into managed storage.",
        requiresConfirmation: true,
        execute: (context, args) => gradeService.prepareDocumentImport(context, args),
      },
    };
  }

  return {
    excel,
    vision,
    pythonBridge,
    createActionTools,
  };
}

