import fs from "fs/promises";
import path from "path";
import { v4 as uuidv4 } from "uuid";

export function isoNow() {
  return new Date().toISOString();
}

export function compactTimestamp() {
  const now = new Date();
  const yyyy = now.getFullYear();
  const mm = String(now.getMonth() + 1).padStart(2, "0");
  const dd = String(now.getDate()).padStart(2, "0");
  const hh = String(now.getHours()).padStart(2, "0");
  const min = String(now.getMinutes()).padStart(2, "0");
  const ss = String(now.getSeconds()).padStart(2, "0");
  return `${yyyy}${mm}${dd}_${hh}${min}${ss}`;
}

export function sanitizeClassFilename(fileName, fallback = "class1.xlsx") {
  const base = (fileName || "").trim();
  if (!base) return fallback;
  const sanitized = base
    .replace(/[<>:"/\\|?*\u0000-\u001F]/g, "_")
    .replace(/\s+/g, "_");
  return sanitized || fallback;
}

export function parseYesNo(text) {
  if (!text || typeof text !== "string") return null;
  const normalized = text.trim().toLowerCase();
  if (
    /^(y|yes|yes please|confirm|confirmed|ok|okay|proceed|go ahead)\b/.test(
      normalized,
    )
  ) {
    return "yes";
  }
  if (/^(n|no|nope|cancel|stop|abort)\b/.test(normalized)) {
    return "no";
  }
  return null;
}

export function validateScore(score, min = 0, max = 100) {
  if (score === null || score === undefined || score === "") return false;
  const numeric = Number(score);
  if (!Number.isFinite(numeric)) return false;
  return numeric >= min && numeric <= max;
}

export function clampScore(score, min = 0, max = 100) {
  const numeric = Number(score);
  if (!Number.isFinite(numeric)) return min;
  return Math.max(min, Math.min(max, numeric));
}

export function parseStudentScorePairs(text) {
  if (!text || typeof text !== "string") return [];
  const pairs = [];
  const body = text
    .replace(/^.*?:/u, "")
    .trim();
  const segments = body
    .split(",")
    .map((segment) => segment.trim())
    .filter(Boolean);

  for (const segment of segments) {
    const match = segment.match(/^(.+?)\s+(-?\d+(?:\.\d+)?)$/);
    if (!match) continue;
    const student = match[1].trim();
    const score = Number(match[2]);
    if (!student) continue;
    pairs.push({ student, score });
  }
  return pairs;
}

export function detectOutliers(values = []) {
  const nums = values
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value));
  if (nums.length < 4) return [];

  const sorted = [...nums].sort((a, b) => a - b);
  const q1 = percentile(sorted, 25);
  const q3 = percentile(sorted, 75);
  const iqr = q3 - q1;
  if (iqr <= 0) return [];

  const lower = q1 - 1.5 * iqr;
  const upper = q3 + 1.5 * iqr;
  return nums.filter((score) => score < lower || score > upper);
}

function percentile(sortedValues, percentileValue) {
  if (!sortedValues.length) return 0;
  const index = (percentileValue / 100) * (sortedValues.length - 1);
  const lower = Math.floor(index);
  const upper = Math.ceil(index);
  if (lower === upper) return sortedValues[lower];
  const fraction = index - lower;
  return (
    sortedValues[lower] + (sortedValues[upper] - sortedValues[lower]) * fraction
  );
}

export async function createBackup(sourcePath, backupsRoot) {
  const stamp = compactTimestamp();
  const uid = uuidv4().slice(0, 8);
  const folder = path.join(backupsRoot, `${stamp}_${uid}`);
  await fs.mkdir(folder, { recursive: true });

  const baseName = path.basename(sourcePath);
  const targetPath = path.join(folder, baseName);

  try {
    await fs.access(sourcePath);
    await fs.copyFile(sourcePath, targetPath);
    return { backupPath: targetPath, existed: true };
  } catch {
    const markerPath = path.join(folder, `${baseName}.new-file.txt`);
    const marker = [
      `No previous file existed for: ${sourcePath}`,
      `Backup marker created at: ${isoNow()}`,
    ].join("\n");
    await fs.writeFile(markerPath, marker, "utf8");
    return { backupPath: markerPath, existed: false };
  }
}

export function summarizeRowsForPreview(rows = [], maxRows = 5) {
  if (!Array.isArray(rows) || rows.length === 0) {
    return "No rows found.";
  }
  const head = rows.slice(0, maxRows);
  return head
    .map((row, index) => `${index + 1}. ${JSON.stringify(row)}`)
    .join("\n");
}

export function normalizeUserId(userId) {
  return String(userId || "unknown").replace(/[^\w.-]/g, "_");
}

