import pRetry from "p-retry";
import { parseStudentScorePairs, parseYesNo } from "../tools/common.js";
import { postOllamaChat } from "../tools/ollama-http.js";

const SYSTEM_PROMPT =
  "You are GradeBot, a reliable and accurate assistant for teachers. Your job is to eliminate all manual grade encoding and calculations so teachers have more time for actual teaching. Always reply in clear English. Never guess numbers. Always create a timestamped backup before any change. Always ask for explicit yes/no confirmation before writing or overwriting any file. Use the Python tools for all calculations, statistics, and reports. Be concise, professional, and proactive. You are powered by Qwen3-VL which excels at reading score sheets from photos.";

function extractClassFileHint(text) {
  if (!text) return null;
  const match = text.match(/(?:for|to|in|as)\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i);
  return match ? match[1] : null;
}

function parseRuleBasedIntent(text) {
  if (!text) return { intent: "unknown" };
  const normalized = text.trim();

  const summarizeMatch = normalized.match(
    /(?:summarize|summary|analy[sz]e|overview|insights?|stats?).*(?:for|of|on|my)?\s*([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
  );
  if (summarizeMatch) {
    return { intent: "calculate_stats", classFile: summarizeMatch[1] };
  }

  const addMatch = normalized.match(/^add to\s+([^\s:]+)\s*:\s*(.+)$/i);
  if (addMatch) {
    return {
      intent: "add_scores",
      classFile: addMatch[1],
      studentScores: parseStudentScorePairs(addMatch[2]),
    };
  }

  const statsMatch = normalized.match(
    /(?:calculate|compute).*(?:full\s+)?(?:stats|statistics|rankings).*(?:for|on)\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
  );
  if (statsMatch) {
    return { intent: "calculate_stats", classFile: statsMatch[1] };
  }

  const reportMatch = normalized.match(
    /generate.*(?:parent\s+)?(?:pdf\s+)?report.*for\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
  );
  if (reportMatch) {
    return { intent: "generate_report", classFile: reportMatch[1] };
  }

  const curveMatch = normalized.match(
    /apply\s+(gentle|bell|custom)?\s*curve\s+(?:to|for)\s+([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
  );
  if (curveMatch) {
    const modeHint = (curveMatch[1] || "gentle").toLowerCase();
    const mode =
      modeHint === "custom"
        ? "custom_linear"
        : modeHint === "bell"
          ? "bell"
          : "gentle_bell";
    return { intent: "apply_curve", classFile: curveMatch[2], mode };
  }

  if (/backup all/i.test(normalized)) {
    return { intent: "backup_all" };
  }

  const importMatch = normalized.match(
    /(?:import|use)\s+(?:as\s+)?([a-zA-Z0-9._-]+\.(?:xlsx|csv))/i,
  );
  if (importMatch) {
    return { intent: "import_document", classFile: importMatch[1] };
  }

  if (/^(help|menu|what can you do)\b/i.test(normalized)) {
    return { intent: "help" };
  }

  return { intent: "unknown" };
}

function stripThinkTags(text) {
  return text.replace(/<think>[\s\S]*?<\/think>/g, "").trim();
}

function parseJsonLoose(rawText) {
  const text = stripThinkTags(String(rawText || "")).trim();
  if (!text) return null;
  try {
    return JSON.parse(text);
  } catch {
    const firstBrace = text.indexOf("{");
    const lastBrace = text.lastIndexOf("}");
    if (firstBrace >= 0 && lastBrace > firstBrace) {
      try {
        return JSON.parse(text.slice(firstBrace, lastBrace + 1));
      } catch {
        return null;
      }
    }
    return null;
  }
}

function helpMessage() {
  return [
    "I can help with grade encoding, calculations, and reporting.",
    "Examples:",
    "- Add to math.xlsx: Alice 94, Bob 87, Charlie 91",
    "- Calculate full stats and rankings for science.xlsx",
    "- Generate parent PDF report for english.xlsx",
    "- Apply gentle curve to class1.xlsx",
    "- Backup all my files",
    "You can also send an Excel/CSV file or a photo of a paper score sheet.",
  ].join("\n");
}

export class GradeAgent {
  constructor({ config, logger, tools, gradeService }) {
    this.config = config;
    this.logger = logger;
    this.tools = tools;
    this.gradeService = gradeService;
