      "- Do not invent student scores.",
      "- Keep classFile null if not provided.",
      "- studentScores must be empty unless clearly provided.",
      "",
      "Recent conversation:",
      historySnippet || "(none)",
      "",
      `Current message: ${text}`,
    ].join("\n");

