import dotenv from "dotenv";
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

dotenv.config();

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const PROJECT_ROOT = path.resolve(__dirname, "..");

function resolveFromProject(inputPath) {
  if (!inputPath) {
    return PROJECT_ROOT;
  }
  return path.isAbsolute(inputPath)
    ? inputPath
    : path.resolve(PROJECT_ROOT, inputPath);
}

const DATA_DIR = resolveFromProject(process.env.DATA_DIR || "./data");
const WA_SESSION_DIR = resolveFromProject(
  process.env.WA_SESSION_DIR || path.join(DATA_DIR, "wa-session"),
);

function parseBoolean(value, defaultValue = false) {
  if (value === undefined || value === null || value === "") return defaultValue;
  return String(value).trim().toLowerCase() === "true";
}

function parseInteger(value, defaultValue) {
  const parsed = Number.parseInt(String(value ?? ""), 10);
  return Number.isFinite(parsed) ? parsed : defaultValue;
}

export const config = Object.freeze({
  app: {
    name: process.env.BOT_NAME || "GradeBot",
    logLevel: process.env.LOG_LEVEL || "info",
    singleNumberMode: parseBoolean(process.env.SINGLE_NUMBER_MODE, true),
    agentTimeoutMs: parseInteger(process.env.AGENT_TIMEOUT_MS, 180000),
  },
  ollama: {
    baseUrl: process.env.OLLAMA_BASE_URL || "http://127.0.0.1:11434",
    model: process.env.OLLAMA_MODEL || "qwen3-vl:8b",
    requestTimeoutMs: 120000,
    retries: 3,
  },
  python: {
    bin: process.env.PYTHON_BIN || "python",
    scriptsDir: path.join(PROJECT_ROOT, "python"),
  },
  paths: {
    projectRoot: PROJECT_ROOT,
    data: DATA_DIR,
    grades: path.join(DATA_DIR, "grades"),
    backups: path.join(DATA_DIR, "backups"),
    logs: path.join(DATA_DIR, "logs"),
    memory: path.join(DATA_DIR, "memory"),
    inbox: path.join(DATA_DIR, "inbox"),
    reports: path.join(DATA_DIR, "reports"),
    waSession: WA_SESSION_DIR,
  },
  limits: {
    minScore: 0,
    maxScore: 100,
    maxConversationItems: 20,
  },
  loopGuard: {
    processedMessageTtlMs: parseInteger(
      process.env.LOOP_GUARD_MESSAGE_TTL_MS,
      10 * 60 * 1000,
    ),
    botMessageIdTtlMs: parseInteger(
      process.env.LOOP_GUARD_BOT_ID_TTL_MS,
      5 * 60 * 1000,
    ),
    botMessageTextTtlMs: parseInteger(
      process.env.LOOP_GUARD_BOT_TEXT_TTL_MS,
      2 * 60 * 1000,
    ),
    maxCacheEntries: parseInteger(process.env.LOOP_GUARD_MAX_CACHE, 5000),
  },
  replyRouting: {
    verifyTimeoutMs: parseInteger(process.env.REPLY_VERIFY_TIMEOUT_MS, 1500),
    enableFallback: parseBoolean(process.env.ENABLE_REPLY_FALLBACK, true),
    strategy: process.env.ONE_NUMBER_REPLY_STRATEGY || "dual_fallback",
  },
  supported: {
    gradeExtensions: [".xlsx", ".csv"],
    imageExtensions: [".jpg", ".jpeg", ".png", ".webp"],
  },
});

export function ensureRuntimeDirectories() {
  const directories = Object.values(config.paths);
  for (const dirPath of directories) {
    fs.mkdirSync(dirPath, { recursive: true });
  }
}

import fs from "fs/promises";
import pRetry from "p-retry";
import { validateScore } from "./common.js";
import { postOllamaChat } from "./ollama-http.js";

function parseModelJson(rawContent) {
  const text = String(rawContent || "")
    .replace(/<think>[\s\S]*?<\/think>/g, "")
    .trim();
  if (!text) {
    throw new Error("Vision model returned empty output.");
  }
  try {
    return JSON.parse(text);
  } catch {
    const firstBrace = text.indexOf("{");
    const lastBrace = text.lastIndexOf("}");
    if (firstBrace >= 0 && lastBrace > firstBrace) {
      return JSON.parse(text.slice(firstBrace, lastBrace + 1));
    }
    throw new Error("Failed to parse JSON from vision output.");
  }
}

export function createVisionTool({ config, logger }) {
  async function extractScoresFromImage({ imagePath, suggestedClassFile }) {
    const imageBuffer = await fs.readFile(imagePath);
    const base64Image = imageBuffer.toString("base64");

    const prompt = [
      "Extract a score sheet from this image.",
      "Return strict JSON with this structure:",
      '{ "classFile": "optional_filename.xlsx", "rows": [{"student":"Name","score":95}], "warnings": ["..."] }',
      "Rules:",
      "- student must be non-empty string",
      "- score must be numeric",
      "- do not invent missing scores",
      "- if uncertain, add warning",
      `- preferred class file if known: ${suggestedClassFile || "class1.xlsx"}`,
    ].join("\n");

    const doRequest = async () => {
      const response = await postOllamaChat({
        baseUrl: config.ollama.baseUrl,
        model: config.ollama.model,
        timeoutMs: config.ollama.requestTimeoutMs,
        logger,
        stream: false,
        messages: [
          {
            role: "user",
            content: prompt,
            images: [base64Image],
          },
        ],
      });
      const content = response?.data?.message?.content;
      if (!content) {
        throw new Error("Ollama vision response is missing content.");
      }
      return parseModelJson(content);
    };

    const parsed = await pRetry(doRequest, {
      retries: Math.max(0, (config.ollama.retries || 1) - 1),
      factor: 2,
      minTimeout: 800,
      maxTimeout: 5000,
      onFailedAttempt: (error) => {
        logger.warn(
          `Vision retry ${error.attemptNumber} failed: ${error.message}`,
        );
      },
    });

    const rawRows = Array.isArray(parsed.rows) ? parsed.rows : [];
    const rows = [];
    const warnings = Array.isArray(parsed.warnings) ? [...parsed.warnings] : [];

    for (const row of rawRows) {
      const student = String(row?.student || "").trim();
      const score = Number(row?.score);
      if (!student) {
        warnings.push("A row was skipped because student name was missing.");
        continue;
      }
      if (!validateScore(score, config.limits.minScore, config.limits.maxScore)) {
        warnings.push(
          `A row for "${student}" was skipped because score ${row?.score} is outside 0-100.`,
        );
        continue;
      }
      rows.push({ student, score });
    }

    return {
      classFile: parsed.classFile || suggestedClassFile || "class1.xlsx",
      rows,
      warnings,
      raw: parsed,
    };
  }

  return { extractScoresFromImage };
}

